import{_ as a,c as t,o as s,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Appariement DM et Contrôle d'Accès : Protégez Votre Assistant IA | Tutoriel Clawdbot","description":"Comprendre le mécanisme de protection par appariement DM de Clawdbot, apprendre à approuver les demandes d'appariement d'expéditeurs inconnus via CLI, lister les demandes en attente et gérer la liste autorisée. Ce tutoriel couvre le flux d'appariement, l'utilisation des commandes CLI, la configuration des stratégies d'accès et les bonnes pratiques de sécurité, incluant le dépannage des erreurs courantes et la commande doctor.","frontmatter":{"title":"Appariement DM et Contrôle d'Accès : Protégez Votre Assistant IA | Tutoriel Clawdbot","sidebarTitle":"Gérer les Accès d'Inconnus","subtitle":"Appariement DM et Contrôle d'Accès : Protégez Votre Assistant IA","description":"Comprendre le mécanisme de protection par appariement DM de Clawdbot, apprendre à approuver les demandes d'appariement d'expéditeurs inconnus via CLI, lister les demandes en attente et gérer la liste autorisée. Ce tutoriel couvre le flux d'appariement, l'utilisation des commandes CLI, la configuration des stratégies d'accès et les bonnes pratiques de sécurité, incluant le dépannage des erreurs courantes et la commande doctor.","tags":["Démarrage","Sécurité","Appariement","Contrôle d'accès"],"prerequisite":["start-gateway-startup"],"order":50},"headers":[],"relativePath":"fr/moltbot/moltbot/start/pairing-approval/index.md","filePath":"fr/moltbot/moltbot/start/pairing-approval/index.md"}`),r={name:"fr/moltbot/moltbot/start/pairing-approval/index.md"};function n(o,e,l,p,d,c){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="appariement-dm-et-controle-d-acces-protegez-votre-assistant-ia" tabindex="-1">Appariement DM et Contrôle d&#39;Accès : Protégez Votre Assistant IA <a class="header-anchor" href="#appariement-dm-et-controle-d-acces-protegez-votre-assistant-ia" aria-label="Permalink to &quot;Appariement DM et Contrôle d&#39;Accès : Protégez Votre Assistant IA&quot;">​</a></h1><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce que vous apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce que vous apprendrez&quot;">​</a></h2><p>Après avoir suivi ce tutoriel, vous serez capable de :</p><ul><li>✅ Comprendre le mécanisme de protection par appariement DM par défaut</li><li>✅ Approuver les demandes d&#39;appariement d&#39;expéditeurs inconnus</li><li>✅ Lister et gérer les demandes d&#39;appariement en attente</li><li>✅ Configurer différentes stratégies d&#39;accès DM (pairing/allowlist/open)</li><li>✅ Exécuter doctor pour vérifier la configuration de sécurité</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Vous avez peut-être configuré un canal WhatsApp ou Telegram et espériez discuter avec l&#39;assistant IA, mais vous rencontrez les problèmes suivants :</p><ul><li>&quot;Pourquoi les inconnus m&#39;envoient-ils des messages et Clawdbot ne répond-il pas ?&quot;</li><li>&quot;J&#39;ai reçu un code d&#39;appariement, je ne sais pas ce que cela signifie&quot;</li><li>&quot;Je veux approuver la demande de quelqu&#39;un mais je ne sais pas quelle commande utiliser&quot;</li><li>&quot;Comment savoir combien de personnes attendent une approbation ?&quot;</li></ul><p>La bonne nouvelle est que <strong>Clawdbot active par défaut la protection par appariement DM</strong>, ce qui garantit que seuls les expéditeurs que vous avez autorisés peuvent converser avec l&#39;assistant IA.</p><h2 id="quand-utiliser-cette-approche" tabindex="-1">Quand utiliser cette approche <a class="header-anchor" href="#quand-utiliser-cette-approche" aria-label="Permalink to &quot;Quand utiliser cette approche&quot;">​</a></h2><p>Lorsque vous devez :</p><ul><li>🛡 <strong>Protéger votre vie privée</strong> : Garantir que seules les personnes de confiance peuvent converser avec l&#39;assistant IA</li><li>✅ <strong>Approuver des inconnus</strong> : Permettre à de nouveaux expéditeurs d&#39;accéder à votre assistant IA</li><li>🔒 <strong>Contrôle d&#39;accès strict</strong> : Limiter les droits d&#39;accès aux utilisateurs spécifiques</li><li>📋 <strong>Gestion par lots</strong> : Voir et gérer toutes les demandes d&#39;appariement en attente</li></ul><hr><h2 id="concept-fondamental" tabindex="-1">Concept fondamental <a class="header-anchor" href="#concept-fondamental" aria-label="Permalink to &quot;Concept fondamental&quot;">​</a></h2><h3 id="qu-est-ce-que-l-appariement-dm" tabindex="-1">Qu&#39;est-ce que l&#39;appariement DM ? <a class="header-anchor" href="#qu-est-ce-que-l-appariement-dm" aria-label="Permalink to &quot;Qu&#39;est-ce que l&#39;appariement DM ?&quot;">​</a></h3><p>Clawdbot se connecte aux plateformes de messagerie réelles (WhatsApp, Telegram, Slack, etc.), et les <strong>messages privés (DM) sur ces plateformes sont considérés par défaut comme des entrées non fiables</strong>.</p><p>Pour protéger votre assistant IA, Clawdbot fournit un <strong>mécanisme d&#39;appariement</strong> :</p><div class="info custom-block"><p class="custom-block-title">Flux d&#39;appariement</p><ol><li>Un expéditeur inconnu vous envoie un message</li><li>Clawdbot détecte que cet expéditeur n&#39;est pas autorisé</li><li>Clawdbot renvoie un <strong>code d&#39;appariement</strong> (8 caractères)</li><li>L&#39;expéditeur doit vous fournir le code d&#39;appariement</li><li>Vous approuvez ce code via CLI</li><li>L&#39;ID de l&#39;expéditeur est ajouté à la liste autorisée</li><li>L&#39;expéditeur peut converser normalement avec l&#39;assistant IA</li></ol></div><h3 id="strategie-dm-par-defaut" tabindex="-1">Stratégie DM par défaut <a class="header-anchor" href="#strategie-dm-par-defaut" aria-label="Permalink to &quot;Stratégie DM par défaut&quot;">​</a></h3><p><strong>Tous les canaux utilisent par défaut <code>dmPolicy=&quot;pairing&quot;</code></strong>, ce qui signifie :</p><table tabindex="0"><thead><tr><th>Stratégie</th><th>Comportement</th></tr></thead><tbody><tr><td><code>pairing</code></td><td>Les expéditeurs inconnus reçoivent un code d&#39;appariement, les messages ne sont pas traités (par défaut)</td></tr><tr><td><code>allowlist</code></td><td>Seuls les expéditeurs de la liste <code>allowFrom</code> sont autorisés</td></tr><tr><td><code>open</code></td><td>Autorise tous les expéditeurs (nécessite une configuration explicite <code>&quot;*&quot;</code>)</td></tr><tr><td><code>disabled</code></td><td>Désactive complètement la fonctionnalité DM</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">Rappel de sécurité</p><p>Le mode <code>pairing</code> par défaut est le choix le plus sûr. Sauf si vous avez des besoins spéciaux, ne passez pas en mode <code>open</code>.</p></div><hr><h2 id="🎒-avant-de-commencer" tabindex="-1">🎒 Avant de commencer <a class="header-anchor" href="#🎒-avant-de-commencer" aria-label="Permalink to &quot;🎒 Avant de commencer&quot;">​</a></h2><p>Assurez-vous que vous avez :</p><ul><li>[x] Complété le tutoriel <a href="./../getting-started/">Démarrage Rapide</a></li><li>[x] Complété le tutoriel <a href="./../gateway-startup/">Démarrage du Gateway</a></li><li>[x] Configuré au moins un canal de messagerie (WhatsApp, Telegram, Slack, etc.)</li><li>[x] Le Gateway est en cours d&#39;exécution</li></ul><hr><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-comprendre-l-origine-du-code-d-appariement" tabindex="-1">Étape 1 : Comprendre l&#39;origine du code d&#39;appariement <a class="header-anchor" href="#etape-1-comprendre-l-origine-du-code-d-appariement" aria-label="Permalink to &quot;Étape 1 : Comprendre l&#39;origine du code d&#39;appariement&quot;">​</a></h3><p>Lorsqu&#39;un expéditeur inconnu envoie un message à votre Clawdbot, ils recevront une réponse similaire à :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Clawdbot: access not configured.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Telegram ID: 123456789</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Pairing code: AB3D7X9K</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Ask the bot owner to approve with:</span></span>
<span class="line"><span>clawdbot pairing approve telegram &lt;code&gt;</span></span></code></pre></div><p><strong>Caractéristiques clés du code d&#39;appariement</strong> (source : <code>src/pairing/pairing-store.ts</code>) :</p><ul><li><strong>8 caractères</strong> : Facile à saisir et à mémoriser</li><li><strong>Lettres majuscules et chiffres</strong> : Évite la confusion</li><li><strong>Caractères confus exclus</strong> : Ne contient pas 0, O, 1, I</li><li><strong>Validité de 1 heure</strong> : Expire automatiquement après ce délai</li><li><strong>Maximum 3 demandes en attente</strong> : Les demandes les plus anciennes sont automatiquement nettoyées une fois ce délai dépassé</li></ul><h3 id="etape-2-lister-les-demandes-d-appariement-en-attente" tabindex="-1">Étape 2 : Lister les demandes d&#39;appariement en attente <a class="header-anchor" href="#etape-2-lister-les-demandes-d-appariement-en-attente" aria-label="Permalink to &quot;Étape 2 : Lister les demandes d&#39;appariement en attente&quot;">​</a></h3><p>Exécutez la commande suivante dans le terminal :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span></span></code></pre></div><p><strong>Vous devriez voir</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Pairing requests (1)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌──────────────────┬────────────────┬────────┬──────────────────────┐</span></span>
<span class="line"><span>│ Code            │ ID            │ Meta   │ Requested            │</span></span>
<span class="line"><span>├──────────────────┼────────────────┼────────┼──────────────────────┤</span></span>
<span class="line"><span>│ AB3D7X9K        │ 123456789      │        │ 2026-01-27T10:30:00Z │</span></span>
<span class="line"><span>└──────────────────┴────────────────┴────────┴──────────────────────┘</span></span></code></pre></div><p>S&#39;il n&#39;y a pas de demandes en attente, vous verrez :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending telegram pairing requests.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Canaux pris en charge</p><p>La fonction d&#39;appariement prend en charge les canaux suivants :</p><ul><li>telegram</li><li>whatsapp</li><li>slack</li><li>discord</li><li>signal</li><li>imessage</li><li>msteams</li><li>googlechat</li><li>bluebubbles</li></ul></div><h3 id="etape-3-approuver-la-demande-d-appariement" tabindex="-1">Étape 3 : Approuver la demande d&#39;appariement <a class="header-anchor" href="#etape-3-approuver-la-demande-d-appariement" aria-label="Permalink to &quot;Étape 3 : Approuver la demande d&#39;appariement&quot;">​</a></h3><p>Utilisez le code d&#39;appariement fourni par l&#39;expéditeur pour approuver l&#39;accès :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span></span></code></pre></div><p><strong>Vous devriez voir</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Approved telegram sender 123456789</span></span></code></pre></div><div class="info custom-block"><p class="custom-block-title">Effet après approbation</p><p>Après approbation, l&#39;ID de l&#39;expéditeur (123456789) est automatiquement ajouté à la liste autorisée de ce canal, stocké dans : <code>~/.clawdbot/credentials/telegram-allowFrom.json</code></p></div><h3 id="etape-4-notifier-l-expediteur-optionnel" tabindex="-1">Étape 4 : Notifier l&#39;expéditeur (optionnel) <a class="header-anchor" href="#etape-4-notifier-l-expediteur-optionnel" aria-label="Permalink to &quot;Étape 4 : Notifier l&#39;expéditeur (optionnel)&quot;">​</a></h3><p>Si vous souhaitez notifier automatiquement l&#39;expéditeur, vous pouvez utiliser l&#39;option <code>--notify</code> :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawdbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pairing</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> approve</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> telegram</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AB3D7X9K</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --notify</span></span></code></pre></div><p>L&#39;expéditeur recevra le message suivant (source : <code>src/channels/plugins/pairing-message.ts</code>) :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Clawdbot access approved. Send a message to start chatting.</span></span></code></pre></div><p><strong>Attention</strong> : L&#39;option <code>--notify</code> nécessite que le Gateway Clawdbot soit en cours d&#39;exécution et que ce canal soit actif.</p><h3 id="etape-5-verifier-que-l-expediteur-peut-converser-normalement" tabindex="-1">Étape 5 : Vérifier que l&#39;expéditeur peut converser normalement <a class="header-anchor" href="#etape-5-verifier-que-l-expediteur-peut-converser-normalement" aria-label="Permalink to &quot;Étape 5 : Vérifier que l&#39;expéditeur peut converser normalement&quot;">​</a></h3><p>Demandez à l&#39;expéditeur d&#39;envoyer à nouveau un message, l&#39;assistant IA devrait répondre normalement.</p><hr><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><p>Effectuez les vérifications suivantes pour confirmer que la configuration est correcte :</p><ul><li>[ ] Exécuter <code>clawdbot pairing list &lt;channel&gt;</code> permet de voir les demandes en attente</li><li>[ ] Utiliser <code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> permet d&#39;approuver avec succès</li><li>[ ] Les expéditeurs approuvés peuvent converser normalement avec l&#39;assistant IA</li><li>[ ] Le code d&#39;appariement expire automatiquement après 1 heure (vérifiable en renvoyant un message)</li></ul><hr><h2 id="pieges-a-eviter" tabindex="-1">Pièges à éviter <a class="header-anchor" href="#pieges-a-eviter" aria-label="Permalink to &quot;Pièges à éviter&quot;">​</a></h2><h3 id="erreur-1-code-d-appariement-introuvable" tabindex="-1">Erreur 1 : Code d&#39;appariement introuvable <a class="header-anchor" href="#erreur-1-code-d-appariement-introuvable" aria-label="Permalink to &quot;Erreur 1 : Code d&#39;appariement introuvable&quot;">​</a></h3><p><strong>Message d&#39;erreur</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>No pending pairing request found for code: AB3D7X9K</span></span></code></pre></div><p><strong>Causes possibles</strong> :</p><ul><li>Le code d&#39;appariement a expiré (plus de 1 heure)</li><li>Le code d&#39;appariement a été saisi incorrectement (vérifiez la casse)</li><li>L&#39;expéditeur n&#39;a pas réellement envoyé de message (le code d&#39;appariement n&#39;est généré que lors de la réception d&#39;un message)</li></ul><p><strong>Solution</strong> :</p><ul><li>Demandez à l&#39;expéditeur d&#39;envoyer à nouveau un message pour générer un nouveau code d&#39;appariement</li><li>Assurez-vous que le code d&#39;appariement est correctement copié (attention à la casse)</li></ul><h3 id="erreur-2-le-canal-ne-prend-pas-en-charge-l-appariement" tabindex="-1">Erreur 2 : Le canal ne prend pas en charge l&#39;appariement <a class="header-anchor" href="#erreur-2-le-canal-ne-prend-pas-en-charge-l-appariement" aria-label="Permalink to &quot;Erreur 2 : Le canal ne prend pas en charge l&#39;appariement&quot;">​</a></h3><p><strong>Message d&#39;erreur</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Channel xxx does not support pairing</span></span></code></pre></div><p><strong>Causes possibles</strong> :</p><ul><li>Faute de frappe dans le nom du canal</li><li>Ce canal ne prend pas en charge la fonction d&#39;appariement</li></ul><p><strong>Solution</strong> :</p><ul><li>Exécutez <code>clawdbot pairing list</code> pour voir la liste des canaux pris en charge</li><li>Utilisez le nom correct du canal</li></ul><h3 id="erreur-3-echec-de-la-notification" tabindex="-1">Erreur 3 : Échec de la notification <a class="header-anchor" href="#erreur-3-echec-de-la-notification" aria-label="Permalink to &quot;Erreur 3 : Échec de la notification&quot;">​</a></h3><p><strong>Message d&#39;erreur</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Failed to notify requester: &lt;error details&gt;</span></span></code></pre></div><p><strong>Causes possibles</strong> :</p><ul><li>Gateway n&#39;est pas en cours d&#39;exécution</li><li>Connexion du canal interrompue</li><li>Problème réseau</li></ul><p><strong>Solution</strong> :</p><ul><li>Vérifiez que le Gateway est en cours d&#39;exécution</li><li>Vérifiez l&#39;état de la connexion du canal : <code>clawdbot channels status</code></li><li>N&#39;utilisez pas l&#39;option <code>--notify</code>, notifiez manuellement l&#39;expéditeur</li></ul><hr><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><p>Ce tutoriel a présenté le mécanisme de protection par appariement DM de Clawdbot :</p><ul><li><strong>Sécurité par défaut</strong> : Tous les canaux utilisent par défaut le mode <code>pairing</code> pour protéger votre assistant IA</li><li><strong>Flux d&#39;appariement</strong> : Les expéditeurs inconnus reçoivent un code d&#39;appariement de 8 caractères, vous devez l&#39;approuver via CLI</li><li><strong>Commandes de gestion</strong> : <ul><li><code>clawdbot pairing list &lt;channel&gt;</code> : Lister les demandes en attente</li><li><code>clawdbot pairing approve &lt;channel&gt; &lt;code&gt;</code> : Approuver l&#39;appariement</li></ul></li><li><strong>Emplacement de stockage</strong> : La liste autorisée est stockée dans <code>~/.clawdbot/credentials/&lt;channel&gt;-allowFrom.json</code></li><li><strong>Expiration automatique</strong> : Les demandes d&#39;appariement expirent automatiquement après 1 heure</li></ul><p>Rappelez-vous : <strong>le mécanisme d&#39;appariement est la pierre angulaire de la sécurité de Clawdbot</strong>, garantissant que seules les personnes que vous avez autorisées peuvent converser avec l&#39;assistant IA.</p><hr><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Dans le prochain cours, nous apprendrons le <strong><a href="./../../faq/troubleshooting/">Dépannage : Résoudre les problèmes courants</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Diagnostic rapide et vérification de l&#39;état du système</li><li>Résoudre les problèmes de démarrage du Gateway, de connexion des canaux, d&#39;erreurs d&#39;authentification, etc.</li><li>Méthodes de dépannage pour les échecs d&#39;appel d&#39;outils et l&#39;optimisation des performances</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquer pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-27</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Génération du code d&#39;appariement (8 caractères, exclut les caractères confus)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L173-L181" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>173-181</td></tr><tr><td>Stockage et TTL des demandes d&#39;appariement (1 heure)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L11-L14" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>11-14</td></tr><tr><td>Commande d&#39;approbation d&#39;appariement</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/cli/pairing-cli.ts#L107-L143" target="_blank" rel="noreferrer"><code>src/cli/pairing-cli.ts</code></a></td><td>107-143</td></tr><tr><td>Génération du message de code d&#39;appariement</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-messages.ts#L4-L20" target="_blank" rel="noreferrer"><code>src/pairing/pairing-messages.ts</code></a></td><td>4-20</td></tr><tr><td>Stockage de la liste autorisée</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/pairing/pairing-store.ts#L457-L461" target="_blank" rel="noreferrer"><code>src/pairing/pairing-store.ts</code></a></td><td>457-461</td></tr><tr><td>Liste des canaux prenant en charge <code>pairing</code></td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/channels/plugins/pairing.ts#L11-L16" target="_blank" rel="noreferrer"><code>src/channels/plugins/pairing.ts</code></a></td><td>11-16</td></tr><tr><td>Stratégie DM par défaut (pairing)</td><td><a href="https://github.com/moltbot/moltbot/blob/main/src/config/zod-schema.providers-core.ts#L93" target="_blank" rel="noreferrer"><code>src/config/zod-schema.providers-core.ts</code></a></td><td>93</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>PAIRING_CODE_LENGTH = 8</code> : Longueur du code d&#39;appariement</li><li><code>PAIRING_CODE_ALPHABET = &quot;ABCDEFGHJKLMNPQRSTUVWXYZ23456789&quot;</code> : Jeu de caractères du code d&#39;appariement (exclut 0O1I)</li><li><code>PAIRING_PENDING_TTL_MS = 60 * 60 * 1000</code> : Validité de la demande d&#39;appariement (1 heure)</li><li><code>PAIRING_PENDING_MAX = 3</code> : Nombre maximum de demandes en attente</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>approveChannelPairingCode()</code> : Approuve le code d&#39;appariement et l&#39;ajoute à la liste autorisée</li><li><code>listChannelPairingRequests()</code> : Liste les demandes d&#39;appariement en attente</li><li><code>upsertChannelPairingRequest()</code> : Crée ou met à jour une demande d&#39;appariement</li><li><code>addChannelAllowFromStoreEntry()</code> : Ajoute un expéditeur à la liste autorisée</li></ul></details>`,92)])])}const g=a(r,[["render",n]]);export{m as __pageData,g as default};
